export type ShapeType = 'Heart' | 'Flower' | 'Saturn' | 'Fireworks' | 'Galaxy' | 'Sphere' | 'Custom';

export interface ParticleConfig {
  count: number;
  color: string;
  size: number;
  speed: number;
  shape: ShapeType;
  expansion: number;
  glow: number;
}

export interface HandData {
  x: number;
  y: number;
  z: number;
  pinch: number; // 0 to 1
  palmOpen: boolean;
  active: boolean;
}

export interface AlchemyConfig {
  color: string;
  speed: number;
  density: number;
  description: string;
}

import { ShapeType } from './types';

export const PARTICLE_COUNT = 8000;

export const SHAPE_FORMULAS: Record<ShapeType, (i: number, count: number) => [number, number, number]> = {
  Heart: (i, count) => {
    const t = (i / count) * Math.PI * 2;
    const x = 16 * Math.pow(Math.sin(t), 3);
    const y = 13 * Math.cos(t) - 5 * Math.cos(2 * t) - 2 * Math.cos(3 * t) - Math.cos(4 * t);
    return [x * 0.1, y * 0.1, (Math.random() - 0.5) * 0.5];
  },
  Flower: (i, count) => {
    const t = (i / count) * Math.PI * 2;
    const k = 5;
    const r = Math.cos(k * t) * 2;
    const x = r * Math.cos(t);
    const y = r * Math.sin(t);
    return [x, y, (Math.random() - 0.5) * 0.2];
  },
  Saturn: (i, count) => {
    if (i < count * 0.4) {
      // Sphere core
      const phi = Math.acos(-1 + (2 * i) / (count * 0.4));
      const theta = Math.sqrt(count * 0.4 * Math.PI) * phi;
      return [
        Math.cos(theta) * Math.sin(phi) * 1,
        Math.sin(theta) * Math.sin(phi) * 1,
        Math.cos(phi) * 1
      ];
    } else {
      // Ring
      const angle = Math.random() * Math.PI * 2;
      const r = 1.8 + Math.random() * 0.8;
      const x = Math.cos(angle) * r;
      const y = (Math.random() - 0.5) * 0.1;
      const z = Math.sin(angle) * r;
      // Tilt the ring
      return [x, y * 2 + x * 0.2, z];
    }
  },
  Fireworks: (i, count) => {
    const radius = Math.random() * 2;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    return [
      radius * Math.sin(phi) * Math.cos(theta),
      radius * Math.sin(phi) * Math.sin(theta),
      radius * Math.cos(phi)
    ];
  },
  Galaxy: (i, count) => {
    const angle = 0.1 * i;
    const r = 0.02 * i;
    return [
      r * Math.cos(angle),
      (Math.random() - 0.5) * 0.5,
      r * Math.sin(angle)
    ];
  },
  Sphere: (i, count) => {
    const phi = Math.acos(-1 + (2 * i) / count);
    const theta = Math.sqrt(count * Math.PI) * phi;
    return [
      Math.cos(theta) * Math.sin(phi) * 2,
      Math.sin(theta) * Math.sin(phi) * 2,
      Math.cos(phi) * 2
    ];
  },
  Custom: (i, count) => [
    (Math.random() - 0.5) * 4,
    (Math.random() - 0.5) * 4,
    (Math.random() - 0.5) * 4
  ]
};

import { GoogleGenAI, Type } from "@google/genai";
import { AlchemyConfig } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const generateAlchemyConfig = async (prompt: string): Promise<AlchemyConfig> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Describe a celestial particle system for the following prompt: "${prompt}". Provide technical parameters.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            color: { type: Type.STRING, description: "A hex color code representing the theme." },
            speed: { type: Type.NUMBER, description: "Speed value from 0.1 to 2.0." },
            density: { type: Type.NUMBER, description: "Particle density modifier from 0.5 to 2.0." },
            description: { type: Type.STRING, description: "A poetic one-sentence description of the visual." }
          },
          required: ["color", "speed", "density", "description"]
        }
      }
    });

    const config = JSON.parse(response.text);
    return config;
  } catch (error) {
    console.error("Gemini Alchemy Error:", error);
    return {
      color: "#ffffff",
      speed: 1.0,
      density: 1.0,
      description: "A default cosmic cloud."
    };
  }
};

import React, { useRef, useMemo, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { ParticleConfig, HandData, ShapeType } from '../types';
import { SHAPE_FORMULAS, PARTICLE_COUNT } from '../constants';

interface Props {
  config: ParticleConfig;
  hand: HandData;
}

const ParticleSystem: React.FC<Props> = ({ config, hand }) => {
  const pointsRef = useRef<THREE.Points>(null!);
  const currentShapeRef = useRef<ShapeType>(config.shape);
  const targetPositionsRef = useRef<Float32Array>(new Float32Array(PARTICLE_COUNT * 3));

  // Create initial positions
  const [positions, colors] = useMemo(() => {
    const pos = new Float32Array(PARTICLE_COUNT * 3);
    const cols = new Float32Array(PARTICLE_COUNT * 3);
    const color = new THREE.Color(config.color);

    for (let i = 0; i < PARTICLE_COUNT; i++) {
      const p = SHAPE_FORMULAS[config.shape](i, PARTICLE_COUNT);
      pos[i * 3] = p[0];
      pos[i * 3 + 1] = p[1];
      pos[i * 3 + 2] = p[2];

      cols[i * 3] = color.r;
      cols[i * 3 + 1] = color.g;
      cols[i * 3 + 2] = color.b;

      targetPositionsRef.current[i * 3] = p[0];
      targetPositionsRef.current[i * 3 + 1] = p[1];
      targetPositionsRef.current[i * 3 + 2] = p[2];
    }
    return [pos, cols];
  }, []);

  // Handle shape transitions
  useEffect(() => {
    const targetFormula = SHAPE_FORMULAS[config.shape];
    for (let i = 0; i < PARTICLE_COUNT; i++) {
      const p = targetFormula(i, PARTICLE_COUNT);
      targetPositionsRef.current[i * 3] = p[0];
      targetPositionsRef.current[i * 3 + 1] = p[1];
      targetPositionsRef.current[i * 3 + 2] = p[2];
    }
    currentShapeRef.current = config.shape;
  }, [config.shape]);

  // Update colors when config color changes
  useEffect(() => {
    const color = new THREE.Color(config.color);
    const colorAttr = pointsRef.current.geometry.attributes.color;
    for (let i = 0; i < PARTICLE_COUNT; i++) {
      colorAttr.setXYZ(i, color.r, color.g, color.b);
    }
    colorAttr.needsUpdate = true;
  }, [config.color]);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const positionAttr = pointsRef.current.geometry.attributes.position;

    // Hand tracking influence
    const handX = (hand.x - 0.5) * 10;
    const handY = -(hand.y - 0.5) * 10;
    const expansion = config.expansion * (1 + hand.pinch * 2);

    for (let i = 0; i < PARTICLE_COUNT; i++) {
      const idx = i * 3;

      // Lerp to target shape
      const tx = targetPositionsRef.current[idx] * expansion;
      const ty = targetPositionsRef.current[idx + 1] * expansion;
      const tz = targetPositionsRef.current[idx + 2] * expansion;

      let x = positionAttr.array[idx];
      let y = positionAttr.array[idx + 1];
      let z = positionAttr.array[idx + 2];

      // Interpolate
      x += (tx - x) * 0.05;
      y += (ty - y) * 0.05;
      z += (tz - z) * 0.05;

      // Add subtle motion
      const noise = Math.sin(time * config.speed + i) * 0.02;
      x += noise;
      y += noise;

      // Interaction: Push/Pull towards hand
      if (hand.active) {
        const dx = handX - x;
        const dy = handY - y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 2) {
          const force = (2 - dist) * 0.1 * (hand.palmOpen ? -1 : 1);
          x += (dx / dist) * force;
          y += (dy / dist) * force;
        }
      }

      positionAttr.setXYZ(i, x, y, z);
    }
    positionAttr.needsUpdate = true;

    // Rotate the whole system slowly
    pointsRef.current.rotation.y += 0.002 * config.speed;
    pointsRef.current.rotation.z += 0.001 * config.speed;
  });

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={PARTICLE_COUNT}
          array={positions}
          itemSize={3}
        />
        <bufferAttribute
          attach="attributes-color"
          count={PARTICLE_COUNT}
          array={colors}
          itemSize={3}
        />
      </bufferGeometry>
      <pointsMaterial
        size={config.size}
        vertexColors
        transparent
        opacity={0.8}
        blending={THREE.AdditiveBlending}
        sizeAttenuation
      />
    </points>
  );
};

export default ParticleSystem;

import React, { useEffect, useRef, useState } from 'react';
import { HandData } from '../types';

interface Props {
  onHandUpdate: (data: HandData) => void;
  showPreview: boolean;
}

const HandTracker: React.FC<Props> = ({ onHandUpdate, showPreview }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let hands: any = null;
    let camera: any = null;

    const initTracking = async () => {
      // Load MediaPipe Hands from CDN
      const script = document.createElement('script');
      script.src = 'https://cdn.jsdelivr.net/npm/@mediapipe/hands/hands.js';
      script.async = true;
      document.head.appendChild(script);

      const cameraScript = document.createElement('script');
      cameraScript.src = 'https://cdn.jsdelivr.net/npm/@mediapipe/camera_utils/camera_utils.js';
      cameraScript.async = true;
      document.head.appendChild(cameraScript);

      script.onload = () => {
        // @ts-ignore
        hands = new window.Hands({
          locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`
        });

        hands.setOptions({
          maxNumHands: 1,
          modelComplexity: 1,
          minDetectionConfidence: 0.5,
          minTrackingConfidence: 0.5
        });

        hands.onResults((results: any) => {
          if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
            const landmarks = results.multiHandLandmarks[0];

            // Palm center (roughly landmark 9)
            const palm = landmarks[9];

            // Pinch detection: Distance between thumb tip (4) and index tip (8)
            const thumb = landmarks[4];
            const index = landmarks[8];
            const dist = Math.sqrt(
              Math.pow(thumb.x - index.x, 2) + 
              Math.pow(thumb.y - index.y, 2) + 
              Math.pow(thumb.z - index.z, 2)
            );

            // Hand open detection: Check if fingers are extended relative to palm
            const isHandOpen = landmarks[12].y < landmarks[9].y;

            onHandUpdate({
              x: palm.x,
              y: palm.y,
              z: palm.z,
              pinch: Math.min(dist * 5, 1),
              palmOpen: isHandOpen,
              active: true
            });

            // Draw on preview canvas if needed
            if (showPreview && canvasRef.current && videoRef.current) {
              const ctx = canvasRef.current.getContext('2d');
              if (ctx) {
                ctx.save();
                ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
                ctx.drawImage(results.image, 0, 0, canvasRef.current.width, canvasRef.current.height);
                // Simple landmark drawing
                ctx.fillStyle = "#00ffcc";
                landmarks.forEach((pt: any) => {
                  ctx.beginPath();
                  ctx.arc(pt.x * canvasRef.current!.width, pt.y * canvasRef.current!.height, 3, 0, 2 * Math.PI);
                  ctx.fill();
                });
                ctx.restore();
              }
            }
          } else {
            onHandUpdate({ x: 0.5, y: 0.5, z: 0, pinch: 0, palmOpen: false, active: false });
          }
        });

        if (videoRef.current) {
          // @ts-ignore
          camera = new window.Camera(videoRef.current, {
            onFrame: async () => {
              await hands.send({ image: videoRef.current! });
            },
            width: 320,
            height: 240
          });
          camera.start();
        }
      };
    };

    initTracking().catch(err => {
      console.error(err);
      setError("Failed to initialize camera or tracking.");
    });

    return () => {
      if (camera) camera.stop();
      if (hands) hands.close();
    };
  }, [onHandUpdate, showPreview]);

  return (
    <div className={`fixed bottom-4 right-4 z-50 transition-opacity duration-500 ${showPreview ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
      <div className="relative rounded-lg overflow-hidden border-2 border-cyan-500 shadow-lg shadow-cyan-500/20 bg-black">
        <video ref={videoRef} className="hidden" playsInline muted />
        <canvas ref={canvasRef} width={240} height={180} className="w-48 h-36 scale-x-[-1]" />
        <div className="absolute top-1 left-2 text-[10px] text-cyan-400 font-mono uppercase tracking-widest bg-black/50 px-1 rounded">
          Hand Radar
        </div>
      </div>
      {error && <div className="text-red-500 text-xs mt-2">{error}</div>}
    </div>
  );
};

export default HandTracker;

import React, { useState, useCallback, useEffect } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Stars, Bloom, EffectComposer } from '@react-three/drei';
import ParticleSystem from './components/ParticleSystem';
import HandTracker from './components/HandTracker';
import { ParticleConfig, HandData, ShapeType } from './types';
import { generateAlchemyConfig } from './services/geminiService';

const App: React.FC = () => {
  const [config, setConfig] = useState<ParticleConfig>({
    count: 8000,
    color: '#00d4ff',
    size: 0.05,
    speed: 0.5,
    shape: 'Galaxy',
    expansion: 1,
    glow: 1
  });

  const [handData, setHandData] = useState<HandData>({
    x: 0.5, y: 0.5, z: 0, pinch: 0, palmOpen: false, active: false
  });

  const [showPreview, setShowPreview] = useState(true);
  const [alchemyPrompt, setAlchemyPrompt] = useState('');
  const [isAlchemyLoading, setIsAlchemyLoading] = useState(false);
  const [alchemyDesc, setAlchemyDesc] = useState('Celestial Particle System Active.');

  const handleHandUpdate = useCallback((data: HandData) => {
    setHandData(data);
  }, []);

  const runAlchemy = async () => {
    if (!alchemyPrompt.trim()) return;
    setIsAlchemyLoading(true);
    try {
      const result = await generateAlchemyConfig(alchemyPrompt);
      setConfig(prev => ({
        ...prev,
        color: result.color,
        speed: result.speed,
        expansion: result.density
      }));
      setAlchemyDesc(result.description);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAlchemyLoading(false);
    }
  };

  const shapes: ShapeType[] = ['Galaxy', 'Heart', 'Flower', 'Saturn', 'Fireworks', 'Sphere', 'Custom'];

  return (
    <div className="relative w-full h-screen bg-black overflow-hidden select-none">
      {/* 3D Scene */}
      <div className="absolute inset-0 z-0">
        <Canvas camera={{ position: [0, 0, 10], fov: 45 }}>
          <color attach="background" args={['#000000']} />
          <ambientLight intensity={0.5} />
          <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

          <ParticleSystem config={config} hand={handData} />

          <OrbitControls enablePan={false} enableZoom={true} minDistance={5} maxDistance={20} />

          <React.Suspense fallback={null}>
            <EffectComposer>
              <Bloom luminanceThreshold={0.1} luminanceSmoothing={0.9} height={300} intensity={config.glow} />
            </EffectComposer>
          </React.Suspense>
        </Canvas>
      </div>

      {/* Overlay UI */}
      <div className="absolute top-0 left-0 w-full p-6 z-10 pointer-events-none flex flex-col md:flex-row justify-between items-start">
        {/* Header & Controls */}
        <div className="bg-black/40 backdrop-blur-md border border-white/10 p-6 rounded-2xl w-full max-w-sm pointer-events-auto">
          <div className="mb-6">
            <h1 className="text-3xl font-bold bg-gradient-to-r from-cyan-400 to-purple-500 bg-clip-text text-transparent">
              Celestial AI
            </h1>
            <p className="text-gray-400 text-xs mt-1 uppercase tracking-widest font-mono">Particle Alchemy Engine v2.0</p>
          </div>

          <div className="space-y-4">
            <section>
              <label className="text-[10px] text-cyan-400 uppercase font-mono tracking-widest mb-2 block">Core Geometry</label>
              <div className="grid grid-cols-3 gap-2">
                {shapes.map(s => (
                  <button
                    key={s}
                    onClick={() => setConfig(prev => ({ ...prev, shape: s }))}
                    className={`py-1.5 px-2 text-xs rounded border transition-all ${
                      config.shape === s 
                        ? 'bg-cyan-500/20 border-cyan-400 text-white shadow-[0_0_10px_rgba(34,211,238,0.3)]' 
                        : 'bg-white/5 border-white/10 text-gray-400 hover:border-white/30'
                    }`}
                  >
                    {s}
                  </button>
                ))}
              </div>
            </section>

            <section>
              <div className="flex justify-between items-center mb-2">
                <label className="text-[10px] text-cyan-400 uppercase font-mono tracking-widest">Expansion & Speed</label>
              </div>
              <input 
                type="range" min="0.5" max="3" step="0.1"
                value={config.expansion}
                onChange={(e) => setConfig(prev => ({ ...prev, expansion: parseFloat(e.target.value) }))}
                className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-cyan-500 mb-2"
              />
              <input 
                type="range" min="0.1" max="2" step="0.1"
                value={config.speed}
                onChange={(e) => setConfig(prev => ({ ...prev, speed: parseFloat(e.target.value) }))}
                className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-purple-500"
              />
            </section>

            <section>
              <label className="text-[10px] text-cyan-400 uppercase font-mono tracking-widest mb-2 block">AI Alchemy (Gemini)</label>
              <div className="flex gap-2">
                <input
                  type="text"
                  placeholder="Describe a mood..."
                  value={alchemyPrompt}
                  onChange={(e) => setAlchemyPrompt(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && runAlchemy()}
                  className="flex-1 bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-cyan-400"
                />
                <button 
                  onClick={runAlchemy}
                  disabled={isAlchemyLoading}
                  className="bg-cyan-600 hover:bg-cyan-500 text-white px-4 py-2 rounded-lg text-sm transition-colors disabled:opacity-50"
                >
                  {isAlchemyLoading ? '...' : 'Fuse'}
                </button>
              </div>
            </section>
          </div>
        </div>

        {/* Status Display */}
        <div className="mt-4 md:mt-0 text-right pointer-events-none">
          <div className="bg-black/40 backdrop-blur-md border border-white/10 px-4 py-2 rounded-xl inline-block text-left mb-2">
            <p className="text-[10px] text-purple-400 font-mono uppercase tracking-widest mb-1">Alchemy Status</p>
            <p className="text-white text-sm max-w-[250px] italic">"{alchemyDesc}"</p>
          </div>

          <div className="bg-black/40 backdrop-blur-md border border-white/10 px-4 py-2 rounded-xl inline-block text-left">
            <p className="text-[10px] text-cyan-400 font-mono uppercase tracking-widest mb-1">Tracking HUD</p>
            <div className="flex gap-4 text-xs font-mono">
              <span className={handData.active ? 'text-green-400' : 'text-red-500'}>
                • {handData.active ? 'HAND DETECTED' : 'SEARCHING...'}
              </span>
              <span className="text-white">PINCH: {(handData.pinch * 100).toFixed(0)}%</span>
            </div>
          </div>
        </div>
      </div>

      {/* Helper Legend */}
      <div className="absolute bottom-6 left-6 z-10 pointer-events-none text-left">
        <div className="bg-black/40 backdrop-blur-md border border-white/10 p-4 rounded-xl space-y-2 max-w-xs">
          <h4 className="text-[10px] text-cyan-400 uppercase font-mono tracking-widest">Gesture Guide</h4>
          <ul className="text-[11px] text-gray-300 space-y-1 font-mono">
            <li><span className="text-cyan-400">• MOVE PALM:</span> Orbit particles</li>
            <li><span className="text-cyan-400">• PINCH:</span> Expand core system</li>
            <li><span className="text-cyan-400">• OPEN/CLOSE:</span> Repel/Attract mass</li>
          </ul>
          <button 
            onClick={() => setShowPreview(!showPreview)}
            className="mt-2 text-[10px] text-gray-500 hover:text-white transition-colors pointer-events-auto"
          >
            [TOGGLE CAMERA PREVIEW]
          </button>
        </div>
      </div>

      <HandTracker onHandUpdate={handleHandUpdate} showPreview={showPreview} />
    </div>
  );
};

export default App;

